_path ? asset('storage/'.$t->receipt_path) : '' }}"><div class="category-icon {{ $t->type }}">{{ $t->type==='income'?'↗':'↘' }}</div><div class="transaction-info"><strong>{{ $t->description }}</strong><span>{{ $t->category->name }} · {{ $t->transaction_date->format('d M Y') }} @if($t->receipt_path) · 📎 Bukti @endif</span></div><strong class="amount {{ $t->type }}">{{ $t->type==='income'?'+':'-' }} Rp {{ number_format($t->amount,0,',','.') }}</strong><form method="post" action="{{ route('transactions.destroy',$t) }}">@csrf @method('DELETE')<button class="icon-button" title="Hapus">×</button></form></div>@empty<div class="empty-state"><div>◌</div><h3>Belum ada transaksi</h3><p>Mulai catat pemasukan atau pengeluaranmu.</p></div>@endforelse</div>@endif
